'use client';

import { useState } from 'react';
import type { Metadata } from 'next';
import { SectionHeader } from '@/design-system/components/SectionHeader';
import { ContactInfo } from '@/design-system/components/ContactInfo';
import { Button } from '@/design-system/components/Button';
import { Input } from '@/design-system/components/Input';
import styles from './page.module.css';

export default function ContactPage() {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    const formData = new FormData(e.currentTarget);
    const data = {
      name: formData.get('name') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,
      message: formData.get('message') as string,
    };

    try {
      // For now, just simulate success
      // In production, this would submit to an API route
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      setIsSuccess(true);
      (e.target as HTMLFormElement).reset();
    } catch (err) {
      setError('Failed to send message. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <main className={styles.page}>
      <div className="container">
        <SectionHeader
          eyebrow="Get in Touch"
          title="We'd love to hear from you"
        />

        <div className={styles.bookCta}>
          <p className={styles.bookCtaText}>
            Ready to schedule? Book directly through our online system.
          </p>
          <Button href="/book">Book Directly</Button>
        </div>

        <div className={styles.layout}>
          <ContactInfo />

          <div className={styles.formSection}>
            <h2 className={styles.formTitle}>Send us a message</h2>

            {isSuccess ? (
              <div className={styles.successMessage}>
                <div className={styles.successIcon}>✓</div>
                <h3>Message sent!</h3>
                <p>Thank you for reaching out. We'll get back to you soon.</p>
                <Button 
                  variant="outline" 
                  onClick={() => setIsSuccess(false)}
                  style={{ marginTop: '1rem' }}
                >
                  Send another message
                </Button>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className={styles.form}>
                <Input
                  label="Name"
                  name="name"
                  type="text"
                  required
                  autoComplete="name"
                />

                <Input
                  label="Email"
                  name="email"
                  type="email"
                  required
                  autoComplete="email"
                />

                <Input
                  label="Phone"
                  name="phone"
                  type="tel"
                  autoComplete="tel"
                />

                <Input
                  label="Message"
                  name="message"
                  type="textarea"
                  required
                />

                {error && (
                  <div className={styles.errorMessage}>
                    {error}
                  </div>
                )}

                <div className={styles.submitRow}>
                  <Button type="submit" disabled={isSubmitting}>
                    {isSubmitting ? 'Sending...' : 'Send Message'}
                  </Button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    </main>
  );
}
